package com.example.oidcclient.config;

import com.example.oidcclient.service.CustomOidcUserService;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configuration.WebSecurityConfigurerAdapter;

@Configuration
@EnableWebSecurity
public class SecurityConfig extends WebSecurityConfigurerAdapter {

    @Autowired
    private CustomOidcUserService customOidcUserService;

    @Override
    protected void configure(HttpSecurity http) throws Exception {
        http
            .authorizeRequests()
                .antMatchers("/", "/login**", "/error").permitAll() // Allow access to root, login pages, and error page
                .anyRequest().authenticated() // All other requests require authentication
            .and()
            .oauth2Login() // Enable OAuth2 Login
                .userInfoEndpoint()
                    .oidcUserService(customOidcUserService) // Use our custom OIDC user service
                .and()
            .and()
            .logout()
                .logoutSuccessUrl("/") // Redirect to home page after logout
                .permitAll();
    }
}

