package com.example.oidcclient.model;

import org.springframework.security.core.GrantedAuthority;
import org.springframework.security.oauth2.core.oidc.OidcIdToken;
import org.springframework.security.oauth2.core.oidc.OidcUserInfo;
import org.springframework.security.oauth2.core.oidc.user.DefaultOidcUser;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;

import java.util.Collection;
import java.util.HashMap;
import java.util.Map;

/**
 * A custom OidcUser implementation to easily access ID Token claims.
 * This class wraps the default OidcUser and provides convenience methods
 * to retrieve specific claims.
 */
public class CustomOidcUser extends DefaultOidcUser {

    private final OidcIdToken idToken;
    private final Map<String, Object> customClaims;

    public CustomOidcUser(Collection<? extends GrantedAuthority> authorities, OidcIdToken idToken) {
        super(authorities, idToken);
        this.idToken = idToken;
        this.customClaims = new HashMap<>(idToken.getClaims());
    }

    public CustomOidcUser(Collection<? extends GrantedAuthority> authorities, OidcIdToken idToken, String nameAttributeKey) {
        super(authorities, idToken, nameAttributeKey);
        this.idToken = idToken;
        this.customClaims = new HashMap<>(idToken.getClaims());
    }

    public CustomOidcUser(Collection<? extends GrantedAuthority> authorities, OidcIdToken idToken, OidcUserInfo userInfo) {
        super(authorities, idToken, userInfo);
        this.idToken = idToken;
        this.customClaims = new HashMap<>(idToken.getClaims());
        if (userInfo != null) {
            this.customClaims.putAll(userInfo.getClaims());
        }
    }

    public CustomOidcUser(Collection<? extends GrantedAuthority> authorities, OidcIdToken idToken, OidcUserInfo userInfo, String nameAttributeKey) {
        super(authorities, idToken, userInfo, nameAttributeKey);
        this.idToken = idToken;
        this.customClaims = new HashMap<>(idToken.getClaims());
        if (userInfo != null) {
            this.customClaims.putAll(userInfo.getClaims());
        }
    }

    @Override
    public OidcIdToken getIdToken() {
        return idToken;
    }

    /**
     * Get a specific claim from the ID Token.
     * @param claimName The name of the claim.
     * @param <T> The expected type of the claim value.
     * @return The claim value, or null if not found.
     */
    public <T> T getClaim(String claimName) {
        return (T) idToken.getClaim(claimName);
    }

    /**
     * Get all custom claims derived from ID Token and UserInfo.
     * @return A map of all claims.
     */
    public Map<String, Object> getAllClaims() {
        return new HashMap<>(customClaims);
    }

    /**
     * Example: Get the full name from the 'name' claim if present.
     * @return The full name string.
     */
    public String getFullName() {
        return getClaim("name");
    }

    /**
     * Example: Get the email from the 'email' claim if present.
     * @return The email string.
     */
    public String getEmail() {
        return getClaim("email");
    }

    // You can add more specific getters for claims you frequently use.
}

