package com.example.oidcclient.service;

import com.example.oidcclient.model.CustomOidcUser;
import org.springframework.security.authentication.InternalAuthenticationServiceException;
import org.springframework.security.oauth2.client.oidc.userinfo.OidcUserRequest;
import org.springframework.security.oauth2.client.oidc.userinfo.OidcUserService;
import org.springframework.security.oauth2.core.OAuth2AuthenticationException;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.stereotype.Service;

import java.util.Map;

/**
 * Custom OIDC User Service to process ID Token claims and create a custom user session object.
 */
@Service
public class CustomOidcUserService extends OidcUserService {

    @Override
    public OidcUser loadUser(OidcUserRequest userRequest) throws OAuth2AuthenticationException {
        // Delegate to the default OidcUserService to fetch user info and build the default OidcUser
        OidcUser oidcUser = super.loadUser(userRequest);

        try {
            // Extract ID Token claims
            Map<String, Object> claims = oidcUser.getClaims();

            // Log or process claims as needed
            System.out.println("--- ID Token Claims from " + userRequest.getClientRegistration().getRegistrationId() + " ---");
            claims.forEach((key, value) -> System.out.println(key + ": " + value));
            System.out.println("--------------------------------------------------");

            // Create a custom OidcUser instance that holds the ID Token and potentially other custom logic
            // We use the 'name' claim as the principal name, if available, otherwise 'sub'
            String userNameAttributeName = userRequest.getClientRegistration().getProviderDetails().getUserInfoEndpoint().getUserNameAttributeName();
            if (userNameAttributeName == null || userNameAttributeName.isEmpty()) {
                userNameAttributeName = "sub"; // Default to 'sub' if not configured
            }

            return new CustomOidcUser(oidcUser.getAuthorities(), oidcUser.getIdToken(), oidcUser.getUserInfo(), userNameAttributeName);

        } catch (Exception ex) {
            // Handle any exceptions during claim processing
            throw new InternalAuthenticationServiceException(ex.getMessage(), ex.getCause());
        }
    }
}

