package com.example.oidcclient.controller;

import com.example.oidcclient.model.CustomOidcUser;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;

import java.util.Map;

@Controller
public class WebController {

    @GetMapping("/")
    public String index() {
        return "index"; // Renders index.html
    }

    @GetMapping("/home")
    public String home(Model model, @AuthenticationPrincipal OidcUser oidcUser) {
        if (oidcUser != null) {
            // If you use CustomOidcUser, you can cast it
            CustomOidcUser customOidcUser = (oidcUser instanceof CustomOidcUser) ? (CustomOidcUser) oidcUser : null;

            model.addAttribute("userName", oidcUser.getName());
            model.addAttribute("fullName", oidcUser.getFullName());
            model.addAttribute("email", oidcUser.getEmail());
            model.addAttribute("idTokenClaims", oidcUser.getIdToken().getClaims());
            model.addAttribute("userInfoClaims", oidcUser.getUserInfo() != null ? oidcUser.getUserInfo().getClaims() : Map.of());

            // Example of using custom methods from CustomOidcUser
            if (customOidcUser != null) {
                model.addAttribute("customFullName", customOidcUser.getFullName());
                model.addAttribute("customEmail", customOidcUser.getEmail());
                model.addAttribute("allClaims", customOidcUser.getAllClaims());
            }
        }
        return "home"; // Renders home.html
    }

    @GetMapping("/secured")
    public String securedPage() {
        return "secured"; // Renders secured.html (just a placeholder)
    }
}

